class AccountManager:
    def __init__(self):
        self._balances: Dict[str, Decimal] = {}
        self._locks: Dict[str, threading.Lock] = {}
        self._global_lock = threading.Lock()
    
    def create_account(self, account_id: str, initial_balance: Decimal = Decimal('0')) -> bool:
        with self._global_lock:
            if account_id in self._balances:
                return False
            self._balances[account_id] = initial_balance
            self._locks[account_id] = threading.Lock()
            return True
    
    def get_balance(self, account_id: str) -> Optional[Decimal]:
        with self._global_lock:
            if account_id not in self._balances:
                return None
            lock = self._locks[account_id]
        
        with lock:
            return self._balances[account_id]
    
    def deposit(self, account_id: str, amount: Decimal) -> bool:
        if amount <= 0:
            return False
        
        with self._global_lock:
            if account_id not in self._balances:
                return False
            lock = self._locks[account_id]
        
        with lock:
            self._balances[account_id] += amount
            return True
    
    def withdraw(self, account_id: str, amount: Decimal) -> bool:
        if amount <= 0:
            return False
        
        with self._global_lock:
            if account_id not in self._balances:
                return False
            lock = self._locks[account_id]
        
        with lock:
            if self._balances[account_id] < amount:
                return False
            self._balances[account_id] -= amount
            return True
    
    def transfer(self, from_account: str, to_account: str, amount: Decimal) -> bool:
        if amount <= 0:
            return False
        
        if from_account == to_account:
            return False
        
        with self._global_lock:
            if from_account not in self._balances or to_account not in self._balances:
                return False
            lock1 = self._locks[from_account]
            lock2 = self._locks[to_account]
        
        first_lock, second_lock = (lock1, lock2) if from_account < to_account else (lock2, lock1)
        
        with first_lock:
            with second_lock:
                if self._balances[from_account] < amount:
                    return False
                self._balances[from_account] -= amount
                self._balances[to_account] += amount
                return True
    
    def process_transaction(self, transaction: Transaction) -> bool:
        return self.transfer(
            transaction.from_account,
            transaction.to_account,
            transaction.amount
        )
    
